/**
 * Interactive Feature Wall Section
 * Author: generated by Amazon Q
 * Created: 2024-12-22
 */

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  CheckCircle, 
  FileText, 
  Calendar, 
  Users, 
  BarChart3, 
  Settings,
  Zap,
  Shield,
  Globe,
  Smartphone,
  Database,
  Cloud
} from 'lucide-react';

// Icon mapping for dynamic icon selection
const iconMap = {
  check: CheckCircle,
  doc: FileText,
  calendar: Calendar,
  users: Users,
  chart: BarChart3,
  settings: Settings,
  zap: Zap,
  shield: Shield,
  globe: Globe,
  smartphone: Smartphone,
  database: Database,
  cloud: Cloud,
};

export interface FeatureTile {
  id: string;
  key: string;
  title: string;
  icon: keyof typeof iconMap;
  previewImage: string;
  description?: string;
}

export interface InteractiveFeatureWallProps {
  title?: string;
  subtitle?: string;
  features: FeatureTile[];
  defaultActiveFeature?: string;
  gridColumns?: 2 | 3 | 4;
  previewAspectRatio?: 'square' | 'video' | 'wide';
  showDescriptions?: boolean;
  theme?: 'light' | 'dark' | 'gradient';
  autoRotate?: boolean;
  rotationInterval?: number;
  className?: string;
}

export function InteractiveFeatureWall({
  title = "Explore Our Features",
  subtitle = "Click on any feature to see it in action",
  features = [],
  defaultActiveFeature,
  gridColumns = 3,
  previewAspectRatio = 'video',
  showDescriptions = false,
  theme = 'light',
  autoRotate = false,
  rotationInterval = 5000,
  className = '',
}: InteractiveFeatureWallProps) {
  const [activeFeature, setActiveFeature] = useState<string>(
    defaultActiveFeature || features[0]?.key || ''
  );
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  const activeFeatureData = features.find(f => f.key === activeFeature || f.id === activeFeature);

  useEffect(() => {
    if (!activeFeature && features.length > 0) {
      setActiveFeature(features[0].key);
    }
  }, [features, activeFeature]);

  // Auto-rotation effect
  useEffect(() => {
    if (!autoRotate || isPaused || features.length <= 1) return;

    const interval = setInterval(() => {
      setActiveFeature(current => {
        const currentIndex = features.findIndex(f => f.key === current || f.id === current);
        const nextIndex = (currentIndex + 1) % features.length;
        return features[nextIndex].key;
      });
    }, rotationInterval);

    return () => clearInterval(interval);
  }, [autoRotate, isPaused, features, rotationInterval]);

  const handleFeatureClick = (featureKey: string) => {
    if (featureKey !== activeFeature) {
      setIsImageLoading(true);
      setActiveFeature(featureKey);
      setIsPaused(true);
      // Resume auto-rotation after 10 seconds of manual interaction
      if (autoRotate) {
        setTimeout(() => setIsPaused(false), 10000);
      }
    }
  };

  const handleImageLoad = () => {
    setIsImageLoading(false);
  };

  const getGridCols = () => {
    switch (gridColumns) {
      case 2: return 'grid-cols-2';
      case 3: return 'grid-cols-2 md:grid-cols-3';
      case 4: return 'grid-cols-2 md:grid-cols-4';
      default: return 'grid-cols-2 md:grid-cols-3';
    }
  };

  const getPreviewAspect = () => {
    switch (previewAspectRatio) {
      case 'square': return 'aspect-square';
      case 'video': return 'aspect-video';
      case 'wide': return 'aspect-[21/9]';
      default: return 'aspect-video';
    }
  };

  const getThemeClasses = () => {
    switch (theme) {
      case 'dark':
        return {
          container: 'bg-gray-900 text-white',
          tile: 'bg-gray-800 hover:bg-gray-700 border-gray-700',
          activeTile: 'bg-blue-600 border-blue-500',
          preview: 'bg-gray-800 border-gray-700'
        };
      case 'gradient':
        return {
          container: 'bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-gray-900 dark:to-gray-800',
          tile: 'bg-white/80 hover:bg-white border-gray-200 dark:bg-gray-800/80 dark:hover:bg-gray-700 dark:border-gray-600',
          activeTile: 'bg-blue-600 border-blue-500 text-white',
          preview: 'bg-white border-gray-200 dark:bg-gray-800 dark:border-gray-600'
        };
      default:
        return {
          container: 'bg-gray-50 dark:bg-gray-900',
          tile: 'bg-white hover:bg-gray-50 border-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 dark:border-gray-600',
          activeTile: 'bg-blue-600 border-blue-500 text-white',
          preview: 'bg-white border-gray-200 dark:bg-gray-800 dark:border-gray-600'
        };
    }
  };

  const themeClasses = getThemeClasses();

  if (features.length === 0) {
    return (
      <section className={`py-16 px-4 ${themeClasses.container} ${className}`}>
        <div className="max-w-6xl mx-auto text-center">
          <div className="text-6xl mb-4">🎯</div>
          <h3 className="text-xl font-semibold mb-2">No Features Added</h3>
          <p className="text-gray-600 dark:text-gray-400">
            Add feature tiles to showcase your product capabilities
          </p>
        </div>
      </section>
    );
  }

  return (
    <section className={`py-16 px-4 ${themeClasses.container} ${className}`}>
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        {(title || subtitle) && (
          <div className="text-center mb-12">
            {title && (
              <h2 className="text-3xl md:text-4xl font-bold mb-4">
                {title}
              </h2>
            )}
            {subtitle && (
              <p className="text-lg text-gray-600 dark:text-gray-400 max-w-2xl mx-auto">
                {subtitle}
              </p>
            )}
          </div>
        )}

        <div className="grid lg:grid-cols-2 gap-8 items-start">
          {/* Feature Tiles Grid */}
          <div className="order-2 lg:order-1">
            <div className={`grid ${getGridCols()} gap-4`}>
              {features.map((feature) => {
                const IconComponent = iconMap[feature.icon] || CheckCircle;
                const isActive = activeFeature === feature.key;
                
                return (
                  <motion.button
                    key={feature.id}
                    onClick={() => handleFeatureClick(feature.key)}
                    className={`
                      p-6 rounded-xl border-2 transition-all duration-300 text-left
                      ${isActive ? themeClasses.activeTile : themeClasses.tile}
                      hover:scale-105 hover:shadow-lg
                    `}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    <div className="flex flex-col items-center text-center space-y-3">
                      <div className={`
                        p-3 rounded-lg transition-colors
                        ${isActive ? 'bg-white/20' : 'bg-blue-100 dark:bg-blue-900/30'}
                      `}>
                        <IconComponent 
                          className={`w-6 h-6 ${isActive ? 'text-white' : 'text-blue-600 dark:text-blue-400'}`} 
                        />
                      </div>
                      <h3 className={`font-semibold ${isActive ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                        {feature.title}
                      </h3>
                      {showDescriptions && feature.description && (
                        <p className={`text-sm ${isActive ? 'text-white/80' : 'text-gray-600 dark:text-gray-400'}`}>
                          {feature.description}
                        </p>
                      )}
                    </div>
                  </motion.button>
                );
              })}
            </div>
          </div>

          {/* Preview Area */}
          <div 
            className="order-1 lg:order-2"
            onMouseEnter={() => autoRotate && setIsPaused(true)}
            onMouseLeave={() => autoRotate && setIsPaused(false)}
          >
            <div className={`
              ${getPreviewAspect()} rounded-xl border-2 overflow-hidden relative
              ${themeClasses.preview}
            `}>
              <AnimatePresence mode="wait">
                {activeFeatureData?.previewImage && (
                  <motion.div
                    key={activeFeature}
                    initial={{ opacity: 0, scale: 1.1 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.9 }}
                    transition={{ duration: 0.3 }}
                    className="absolute inset-0"
                  >
                    <img
                      src={activeFeatureData.previewImage}
                      alt={`${activeFeatureData.title} Preview`}
                      className="w-full h-full object-cover"
                      onLoad={handleImageLoad}
                      onError={() => setIsImageLoading(false)}
                    />
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Loading State */}
              {isImageLoading && (
                <div className="absolute inset-0 flex items-center justify-center bg-gray-100 dark:bg-gray-800">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                </div>
              )}

              {/* Fallback when no image */}
              {!activeFeatureData?.previewImage && (
                <div className="absolute inset-0 flex items-center justify-center bg-gray-100 dark:bg-gray-800">
                  <div className="text-center">
                    <div className="text-4xl mb-2">🖼️</div>
                    <p className="text-gray-500 dark:text-gray-400">No preview available</p>
                  </div>
                </div>
              )}
            </div>

            {/* Active Feature Info */}
            {activeFeatureData && (
              <motion.div
                key={activeFeature}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-4 text-center lg:text-left"
              >
                <h3 className="text-xl font-semibold mb-2">
                  {activeFeatureData.title}
                </h3>
                {activeFeatureData.description && (
                  <p className="text-gray-600 dark:text-gray-400">
                    {activeFeatureData.description}
                  </p>
                )}
              </motion.div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

export default InteractiveFeatureWall;